#!/usr/bin/env python3
import json
import os
import tempfile
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def verify_roi_measurement_export(traj, env_info, task_info):
    """
    Verifies the ROI measurement export task.
    """
    copy_from_env = env_info.get('copy_from_env')
    if not copy_from_env:
        return {"passed": False, "score": 0, "feedback": "Copy function not available"}

    # 1. Retrieve the result JSON generated by export_result.sh
    temp_file = tempfile.NamedTemporaryFile(delete=False, suffix='.json')
    try:
        copy_from_env("/tmp/task_result.json", temp_file.name)
        with open(temp_file.name, 'r') as f:
            result = json.load(f)
    except Exception as e:
        return {"passed": False, "score": 0, "feedback": f"Failed to retrieve task results: {str(e)}"}
    finally:
        if os.path.exists(temp_file.name):
            os.unlink(temp_file.name)

    score = 0
    max_score = 100
    feedback_parts = []
    
    # --- Scoring Criteria ---
    
    # 1. CSV Validation (25 pts)
    # Check existence, row count (>=6), and calibration
    csv_score = 0
    if result.get("csv_exists") and result.get("csv_valid"):
        csv_score += 5
        if result.get("csv_rows", 0) >= 6:
            csv_score += 10
            feedback_parts.append("CSV contains sufficient ROIs.")
        else:
            feedback_parts.append(f"CSV has only {result.get('csv_rows')} ROIs (expected >= 6).")
        
        # Check calibration: If area values are small (e.g. < 5000) they are likely microns^2.
        # If pixels (696x520), a small ROI might be ~1000 px, but if it's calibrated (0.65um/px),
        # 1000px = 1000 * 0.65^2 ~= 422 um^2.
        # Uncalibrated full image is ~360,000. Calibrated full image is ~150,000.
        # It's hard to be exact, but we look for "Area" column.
        cols = result.get("csv_cols", [])
        if any("Area" in c for c in cols):
            csv_score += 5
        else:
            feedback_parts.append("CSV missing 'Area' column.")
            
        # Check for heterogeneity (agent didn't just measure the whole image 6 times)
        areas = result.get("area_values", [])
        if len(set(areas)) > 1:
            csv_score += 5
        else:
            feedback_parts.append("All ROI measurements are identical (suspicious).")
    else:
        feedback_parts.append("ROI Measurements CSV missing or invalid.")
    
    score += csv_score
    
    # 2. ROI Set ZIP (20 pts)
    # Check existence and count
    zip_score = 0
    if result.get("zip_exists") and result.get("zip_valid"):
        zip_score += 10
        if result.get("roi_count", 0) >= 6:
            zip_score += 10
            feedback_parts.append("ROI Set ZIP contains sufficient ROIs.")
        else:
            feedback_parts.append(f"ROI Set ZIP has only {result.get('roi_count')} ROIs.")
    else:
        feedback_parts.append("ROI Set ZIP missing.")
        
    score += zip_score
    
    # 3. Annotated Overlay (15 pts)
    # Check existence and size
    png_score = 0
    if result.get("png_exists"):
        png_score += 5
        if result.get("png_size", 0) > 5000: # Arbitrary threshold for non-empty image
            png_score += 10
            feedback_parts.append("Annotated overlay image created.")
        else:
            feedback_parts.append("Overlay image seems too small/empty.")
    else:
        feedback_parts.append("Annotated overlay PNG missing.")
        
    score += png_score
    
    # 4. Summary Report (25 pts)
    # Check existence and content keywords
    report_score = 0
    if result.get("report_exists"):
        report_score += 5
        content = result.get("report_content", "").lower()
        
        # Check for required stats
        if "mean" in content: report_score += 5
        if "cv" in content or "variation" in content or "deviation" in content: report_score += 5
        if "high" in content or "max" in content: report_score += 5
        if any(char.isdigit() for char in content): report_score += 5
        
        feedback_parts.append("Summary report generated.")
    else:
        feedback_parts.append("Summary report missing.")
        
    score += report_score

    # 5. Anti-gaming / Timestamp (15 pts)
    if result.get("timestamps_valid", True):
        score += 15
    else:
        feedback_parts.append("Files detected from before task start! (Anti-gaming penalty)")
        score = 0 # Zero out if cheating detected

    # VLM Verification (Optional trajectory check could go here, but programmatic is strong enough)
    
    passed = score >= 60 and result.get("csv_exists") and result.get("zip_exists")
    
    return {
        "passed": passed,
        "score": score,
        "feedback": " ".join(feedback_parts)
    }